import React from "react"
import { useStaticQuery, graphql } from "gatsby"
import { GatsbyImage } from "gatsby-plugin-image"
import SwiperCore, { Pagination, Autoplay } from 'swiper';
import { Swiper, SwiperSlide } from 'swiper/react'
import { useIntl } from "gatsby-plugin-intl"

SwiperCore.use([Pagination, Autoplay]);

export default function Slider() {
	
  const intl = useIntl()

  const data = useStaticQuery(
    graphql`
      query {
        main: file(sourceInstanceName: {eq: "images"}, base: {eq: "main-slider.jpg"}) {
          childImageSharp {
            gatsbyImageData(layout: FULL_WIDTH)
          }
        }
        tide: file(sourceInstanceName: {eq: "images"}, base: {eq: "tide.png"}) {
          childImageSharp {
            gatsbyImageData(layout: FULL_WIDTH)
          }
        }
      }
    `
  )
	
  return(
    <div className="main-slider">
      <Swiper
        pagination={{ clickable: true }}
        autoplay={{
          delay: 3000,
          disableOnInteraction: true,
        }}
        loop={true}
      >
        <SwiperSlide>
          <GatsbyImage image={data.main.childImageSharp.gatsbyImageData} alt={intl.formatMessage({ id: "pier" })} />
        </SwiperSlide>
        <SwiperSlide>
          <a href="https://tide.pier.or.th/" target="_blank" rel="nofollow noopener noreferrer">
            <GatsbyImage image={data.tide.childImageSharp.gatsbyImageData} alt={intl.formatMessage({ id: "pier" })} />
          </a>
        </SwiperSlide>
      </Swiper>
    </div>
  )

}
