import React from "react"
import { withPrefix, useStaticQuery, graphql } from "gatsby"
import { GatsbyImage } from "gatsby-plugin-image"
import Link from "../components/IntlLink"
import Layout from "../components/Layout"
import SearchBar from "../components/SearchBar"
import { useIntl } from "gatsby-plugin-intl"
import Slider from "../components/Slider"
import PubImage from "../components/PubImage"
import { formatFrontmatterDate, FormattedAuthor, getAuthors } from "../util"

import { MDXRenderer } from 'gatsby-plugin-mdx'

import classNames from "classnames/bind"
import styles from "./styles.module.scss"

export default function Home({ pageContext: { language }, data: { build, home, featuredEconomist, featuredEvent, latestBlog, featured1, featured2, latestDP, latestAbridged, latestEvents } }) {
	
	const cx = classNames.bind(styles);

	const intl = useIntl()

	function foo(node) {
		return node.authors && getAuthors(node.frontmatter.authors, node.authors, language)
	}

	function LatestStuff({ title, latestNode }) {

		return(
			<div className={cx("topItem")}>
				<div className={cx("cellTitle")}>
					{title}
				</div>
				<div className={cx("cellBody", "zoom-hover")}>
					<Link to={latestNode.fields.slug}>
						<div className={"zoom-container"}>
							<PubImage f={latestNode.frontmatter} collection={latestNode.fields.collection} style="cover" />
						</div>
					</Link>
					<div className={cx("latestDetail")}>
						<Link to={latestNode.fields.slug} className={cx("nohover", "nolinkcolor", "top")}>
							{latestNode.frontmatter.title}
						</Link>
						<div className={cx("bottom", "details")}>
							<div className={cx("bottomDate")}>
								{formatFrontmatterDate(latestNode.frontmatter, language)}
							</div>
							<div className={cx("authors")}>
								{foo(latestNode).map((a, i) =>
									<React.Fragment key={`author${i}`}>
										<FormattedAuthor author={a} /><br />
									</React.Fragment>
								)}
							</div>
						</div>
					</div>
				</div>
			</div>
		)
	
	}

	function OtherStuff({ latestNodes, link, className }) {

		return(
			<div className={(className ? className + " " : "") + cx("moreItems")}>
				{latestNodes.map((node, index) =>
					<Link to={node.fields.slug} className="nohover nolinkcolor" key={`other${index}`}>
						<div className={cx("moreItem")}>
							<div className={cx("title")}>{node.frontmatter.title}</div>
							<div className={cx("details")}>{formatFrontmatterDate(node.frontmatter)}</div>
						</div>
					</Link>
				)}
				<Link to={link} className={cx("details", "seeMore")}>{`[ ${language === "th" ? "ดูเพิ่มเติม" : "See more"} ]`}</Link>
			</div>
		)

	}

  return(
  	<Layout
			lang={language}
			indexThis={false}
			noBanner={true}
			customTitle={true}
			title={intl.formatMessage({ id: "pier" })}
			top={
				<React.Fragment>
					<Slider />
					<SearchBar />
				</React.Fragment>
			}
		>

			<div className={cx("flexContainer", "topFlex")}>
				<LatestStuff title="Discussion Paper" latestNode={latestDP.nodes[0]} />
				<OtherStuff className={cx("dpMore")} title="Discussion Paper" link="/dp/" latestNodes={latestDP.nodes.slice(1)} />
				<LatestStuff title="aBRIDGEd" latestNode={latestAbridged.nodes[0]} />
				<OtherStuff className={cx("abMore")} title="aBRIDGEd" link="/abridged/" latestNodes={latestAbridged.nodes.slice(1)} />
			</div>
			
			<hr />

			<div className={cx("bottomGrid")}>
				<div className={cx("item", "itemEconomist")}>
					<div className={cx("cellTitle")}>Featured Economist</div>
					<Link to={featuredEconomist.nodes[0].fields.slug}>
						<GatsbyImage image={featuredEconomist.nodes[0].frontmatter.image.childImageSharp.gatsbyImageData} alt="xx" />
					</Link>
					<div className={cx("top", "nohover", "nolinkcolor")}>
						<Link to={featuredEconomist.nodes[0].fields.slug} className={cx("nohover", "nolinkcolor")}>
							{featuredEconomist.nodes[0].frontmatter.title}
						</Link>
					</div>
					<div className={cx("body")}>
						{featuredEconomist.nodes[0].excerpt}
					</div>
					<div className={cx("body")}>
						{language === "th" ? "ผลงานล่าสุด : " : "Latest article: "}
						<Link to={featuredEconomist.nodes[0].publications[0].fields.slug}>
							{featuredEconomist.nodes[0].publications[0].frontmatter.title}
						</Link>
					</div>
				</div>
				<div className={cx("item", "itemFeaturedEvent", "zoom-container")}>
					<Link to={featuredEvent.nodes[0].fields.slug}>
						<PubImage f={featuredEvent.nodes[0].frontmatter} collection={featuredEvent.nodes[0].fields.collection} style="square" />
						<div className={cx("top")}>{featuredEvent.nodes[0].frontmatter.title}</div>
						<div className={cx("details")}>
							{formatFrontmatterDate(featuredEvent.nodes[0].frontmatter, language)}<br />
							{featuredEvent.nodes[0].frontmatter.location}
						</div>
					</Link>
				</div>
				<div className={cx("item", "itemLatestEvents")}>
					C
				</div>
				<div className={cx("item", "itemStats")}>
					<div className={cx("pic")}>
						<Link to={latestBlog.nodes[0].fields.slug}>
							<PubImage f={latestBlog.nodes[0].frontmatter} collection="blog" style="fullwidth" objectFit="contain" objectPosition="right 50%" />
						</Link>
					</div>
					<div className={cx("text")}>
						<div className={cx("cellTitle")}>
							<Link to="/blog/">PIER Blog</Link>
						</div>
						<div className={cx("top", "nohover", "nolinkcolor")}>
							<Link to={latestBlog.nodes[0].fields.slug} className={cx("nohover", "nolinkcolor")}>
								{latestBlog.nodes[0].frontmatter.title}
							</Link>
						</div>
						<div className={cx("body")}>
							{latestBlog.nodes[0].excerpt}
						</div>
					</div>
				</div>
			</div>
			
			<div className="date">Last build: {build.currentDate}</div>
			<MDXRenderer>{home.body}</MDXRenderer>

  	</Layout>
  )

}

